const response = $input.item.json;
const rawText = response.output;

let imagePrompts = [], videoPrompts = [], musicPrompts = [], sfxPrompts = [];

try {
  const imgMatch = rawText.match(/IMAGE_PROMPTS[^\[]*([\s\S]*?)(?=VIDEO_PROMPTS|$)/i);
  const vidMatch = rawText.match(/VIDEO_PROMPTS[^\[]*([\s\S]*?)(?=MUSIC_PROMPTS|$)/i);
  const musMatch = rawText.match(/MUSIC_PROMPTS[^\[]*([\s\S]*?)(?=SFX_PROMPTS|$)/i);
  const sfxMatch = rawText.match(/SFX_PROMPTS[^\[]*([\s\S]*?)(?=\n\n[A-Z]|$)/i);

  const extractArray = (match) => {
    if (!match) return [];
    const arrMatch = match[0].match(/\[[\s\S]*\]/);
    if (!arrMatch) return [];
    try { return JSON.parse(arrMatch[0]); } catch(e) { return []; }
  };

  imagePrompts = extractArray(imgMatch);
  videoPrompts = extractArray(vidMatch);
  musicPrompts = extractArray(musMatch);
  sfxPrompts = extractArray(sfxMatch);
} catch(e) {
  console.error('Prompt parse error:', e.message);
}

const prevData = $('Parse Script Response').item.json;

return [{ json: {
  ...prevData,
  imagePrompts,
  videoPrompts,
  musicPrompts,
  sfxPrompts,
  rawPromptsOutput: rawText,
  imageTotalCount: imagePrompts.length,
  videoTotalCount: videoPrompts.length,
  musicTotalCount: musicPrompts.length,
  sfxTotalCount: sfxPrompts.length
}}];

const parsedData = $('Parse Asset Prompts').item.json;
const projectDir = parsedData.projectDir;

const manifest = {
  projectDir,
  topic: parsedData.TOPIC,
  voiceover: projectDir + '/audio/voiceover.mp3',
  images: (parsedData.imagePrompts || []).map(p => ({
    filename: projectDir + '/images/' + p.filename,
    timestamp: p.timestamp,
    duration: 8
  })),
  videos: (parsedData.videoPrompts || []).map(p => ({
    filename: projectDir + '/videos/' + p.filename,
    timestamp: p.timestamp,
    duration: p.duration_seconds || 8
  })),
  music: (parsedData.musicPrompts || []).map(p => ({
    filename: projectDir + '/music/' + p.filename,
    timestamp: p.timestamp,
    duration: p.duration_seconds || 30,
    type: p.type
  })),
  sfx: (parsedData.sfxPrompts || []).map(p => ({
    filename: projectDir + '/sfx/' + p.filename,
    timestamp: p.timestamp,
    duration: p.duration_seconds || 5
  }))
};

return [{ json: { manifest, projectDir, TOPIC: parsedData.TOPIC } }];

const { manifest, projectDir } = $input.item.json;

const slugify = s => s.toLowerCase().replace(/[^a-z0-9]+/g, '_').substring(0, 40);
const outputFile = `/Users/jneal/Antigravity/out/${slugify(manifest.topic)}_final.mp4`;
const concatFile = `${projectDir}/scripts/video_concat.txt`;
const musicMixFile = `${projectDir}/scripts/music_concat.txt`;

// Build concat list from videos and images sorted by timestamp
const allVisuals = [
  ...manifest.images.map(i => ({ ...i, mediaType: 'image' })),
  ...manifest.videos.map(v => ({ ...v, mediaType: 'video' }))
].sort((a, b) => {
  const toSec = t => { const [m,s] = (t||'0:00').split(':'); return parseInt(m)*60+parseInt(s); };
  return toSec(a.timestamp) - toSec(b.timestamp);
});

const concatLines = allVisuals.map(v => {
  if (v.mediaType === 'image') {
    return `file '${v.filename}'\nduration ${v.duration || 8}`;
  } else {
    return `file '${v.filename}'`;
  }
}).join('\n');

// Music concat
const musicLines = manifest.music.map(m => `file '${m.filename}'\nduration ${m.duration}`).join('\n');

// Build SFX filter inputs
const sfxInputs = manifest.sfx.map((s, i) => `-i "${s.filename}"`).join(' ');
const sfxMixParts = manifest.sfx.map((_, i) => `[${i + 3}:a]`).join('');
const totalAudioInputs = manifest.sfx.length + 3;
const sfxMixFilter = manifest.sfx.length > 0
  ? `;${sfxMixParts}amix=inputs=${manifest.sfx.length}[sfxmix];[2:a][sfxmix]amix=inputs=2:weights=1 0.15[bgmix];[1:a][bgmix]amix=inputs=2:weights=1 0.25[aout]`
  : ';[1:a][2:a]amix=inputs=2:weights=1 0.20[aout]';

const ffmpegCmd = `#!/bin/bash
set -e

PROJECT_DIR="${projectDir}"
OUTPUT="${outputFile}"

# Write concat file for visuals
cat > "${concatFile}" << 'CONCAT_EOF'
${concatLines}
CONCAT_EOF

# Write music concat
cat > "${musicMixFile}" << 'MUSIC_EOF'
${musicLines}
MUSIC_EOF

# Assemble music track
ffmpeg -y -f concat -safe 0 -i "${musicMixFile}" -c:a libmp3lame -q:a 4 "${projectDir}/audio/music_combined.mp3"

# Final assembly: visuals + voiceover + music + sfx
ffmpeg -y \\
  -f concat -safe 0 -i "${concatFile}" \\
  -i "${manifest.voiceover}" \\
  -i "${projectDir}/audio/music_combined.mp3" \\
  ${sfxInputs} \\
  -filter_complex "[0:v]scale=1920:1080:force_original_aspect_ratio=decrease,pad=1920:1080:(ow-iw)/2:(oh-ih)/2,setsar=1,fps=30[vout]${sfxMixFilter}" \\
  -map "[vout]" -map "[aout]" \\
  -c:v libx264 -crf 18 -preset slow -profile:v high \\
  -c:a aac -b:a 192k -ar 48000 \\
  -movflags +faststart \\
  -t $(ffprobe -v quiet -show_entries format=duration -of csv=p=0 "${manifest.voiceover}") \\
  "$OUTPUT"

echo "Assembly complete: $OUTPUT"
`;

return [{ json: { ffmpegScript: ffmpegCmd, outputFile, scriptPath: `${projectDir}/scripts/assemble.sh`, projectDir, TOPIC: manifest.topic } }];

const d = $input.item.json;
const prompts = d.imagePrompts || [];
return prompts.map((p, i) => {
  const rowNum = i + 1;
  const promptJson = typeof p.nb2_prompt === 'object'
    ? JSON.stringify(p.nb2_prompt)
    : (p.nb2_prompt || '');
  return {
    json: {
      'Index':    rowNum,
      'Type':     'Image',
      'Prompt':   '"' + promptJson + '"',
      'Filename': 'image_' + String(rowNum).padStart(4, '0')
    }
  };
});

const parsedData = $('Parse Asset Prompts').item.json;
const prompts = parsedData.videoPrompts || [];
return prompts.map((p, i) => {
  const rowNum = i + 1;
  const promptText = p.veo_prompt || '';
  return {
    json: {
      'Index':    rowNum,
      'Type':     'Video',
      'Prompt':   '"' + promptText + '"',
      'Filename': 'video_' + String(rowNum).padStart(4, '0')
    }
  };
});

const d = $input.item.json;
const prompts = d.musicPrompts || [];
return prompts.map(p => ({ json: { ...p, projectDir: d.projectDir } }));

const d = $input.item.json;
const prompts = d.sfxPrompts || [];
return prompts.map(p => ({ json: { ...p, projectDir: d.projectDir } }));

const enhancedText = $input.item.json.output || '';
const projectVars   = $('Set Project Variables').item.json;
const audioDir      = projectVars.projectDir + '/audio';
const MAX_CHARS     = 4500;

// Smart split: respect sentence boundaries and <break/> tags
function chunkText(text, maxLen) {
  // Split on sentence-ending punctuation followed by whitespace
  const sentenceRe = /[^.!?<]*(?:<[^>]+>)*[^.!?]*[.!?]+(?:\s+|$)/g;
  const sentences = [];
  let m;
  let last = 0;
  while ((m = sentenceRe.exec(text)) !== null) {
    sentences.push(m[0]);
    last = sentenceRe.lastIndex;
  }
  if (last < text.length) sentences.push(text.slice(last));

  const chunks = [];
  let current = '';
  for (const s of sentences) {
    if (s.length > maxLen) {
      // Sentence itself too long — split at last space before limit
      if (current) { chunks.push(current.trim()); current = ''; }
      let rem = s;
      while (rem.length > maxLen) {
        const cut = rem.lastIndexOf(' ', maxLen);
        chunks.push(rem.slice(0, cut > 0 ? cut : maxLen).trim());
        rem = rem.slice(cut > 0 ? cut + 1 : maxLen);
      }
      current = rem;
    } else if (current.length + s.length > maxLen) {
      chunks.push(current.trim());
      current = s;
    } else {
      current += s;
    }
  }
  if (current.trim()) chunks.push(current.trim());
  return chunks;
}

const chunks = chunkText(enhancedText, MAX_CHARS);
const padded  = n => String(n).padStart(2, '0');

// Build a bash write script using unique EOF markers per chunk
let writeScript = `mkdir -p "${audioDir}"\n`;
chunks.forEach((chunk, i) => {
  const num    = padded(i + 1);
  const marker = `RUINS_CHUNK_${num}_EOF`;
  writeScript += `cat > "${audioDir}/voiceover_chunk_${num}.txt" << '${marker}'\n${chunk}\n${marker}\n\n`;
});

// Instructions file
const lastNum = padded(chunks.length);
const instMarker = 'RUINS_INST_EOF';
writeScript += `cat > "${audioDir}/VOICEOVER_INSTRUCTIONS.txt" << '${instMarker}'\n`;
writeScript += `RUINS UNTOLD — VOICEOVER INSTRUCTIONS\n`;
writeScript += `======================================\n`;
writeScript += `Chunks : ${chunks.length}\n`;
writeScript += `Model  : eleven_v3\n`;
writeScript += `Voice  : [Your ElevenLabs Voice — paste your voice name here]\n\n`;
writeScript += `For each chunk (voiceover_chunk_01.txt → voiceover_chunk_${lastNum}.txt):\n`;
writeScript += `  1. Open the .txt file\n`;
writeScript += `  2. Paste into ElevenLabs (eleven_v3 model)\n`;
writeScript += `  3. Generate + download MP3\n`;
writeScript += `  4. Save as chunk_01.mp3 → chunk_${lastNum}.mp3 IN THIS FOLDER\n\n`;
writeScript += `When all ${chunks.length} MP3s are present, return to n8n and approve.\n`;
writeScript += `${instMarker}\n`;
writeScript += `echo "Wrote ${chunks.length} voiceover chunks to ${audioDir}"\n`;

return [{
  json: {
    ...projectVars,
    chunkCount:  chunks.length,
    audioDir:    audioDir,
    writeScript: writeScript,
    chunkSizes:  chunks.map((c, i) => `chunk_${padded(i+1)}: ${c.length} chars`)
  }
}];

// Source chunk data from the Parse node (Write Voiceover Chunks loses JSON context)
const chunkData = $('Parse & Chunk Voiceover').item.json;
const chunks    = chunkData.chunks;
const audioDir  = chunkData.audioDir;
const padded    = n => String(n).padStart(2, '0');

// Reset request-id chain for a fresh voiceover run
const staticData = $getWorkflowStaticData('global');
staticData.ruinsVoicePrevIds = [];

return chunks.map((chunkText, i) => ({
  json: {
    TOPIC:        chunkData.TOPIC,
    VOICE_ID:     chunkData.VOICE_ID,
    projectSlug:  chunkData.projectSlug,
    projectDir:   chunkData.projectDir,
    audioDir:     audioDir,
    chunkIndex:   i,
    chunkNumber:  padded(i + 1),
    chunkText:    chunkText,
    chunkCount:   chunks.length,
    isFirstChunk: i === 0,
    filename:     `${audioDir}/chunk_${padded(i + 1)}.mp3`
  }
}));

const item       = $input.item.json;
const staticData = $getWorkflowStaticData("global");

const kieInput = {
  dialogue: [
    {
      text:  item.chunkText,
      voice: "4YYIPFl9wE5c4L2eu2Gb"  // Ruins Untold voice ID
    }
  ],
  stability: 0
};

// Chain previous_request_ids for voice continuity (chunks 2+)
if (!item.isFirstChunk && staticData.ruinsVoicePrevIds && staticData.ruinsVoicePrevIds.length > 0) {
  kieInput.previous_request_ids = staticData.ruinsVoicePrevIds.slice(-3);
}

const kieBody = {
  model: "elevenlabs/text-to-dialogue-v3",
  input: kieInput
};

return [{
  json: {
    ...item,
    kieBody:         JSON.stringify(kieBody),
    includedPrevIds: kieInput.previous_request_ids || []
  }
}];

const response  = $input.item.json;
const chunkMeta = $('Prepare Chunk Request').item.json;

if (response.code !== 200) {
  throw new Error(`Kie.ai createTask failed (chunk ${chunkMeta.chunkNumber}): ${response.msg}`);
}

const taskId = response.data.taskId;

return [{
  json: {
    ...chunkMeta,
    kieTaskId: taskId
  }
}];

const pollResponse = $input.item.json;
const chunkMeta    = $('Prepare Chunk Request').item.json;
const staticData   = $getWorkflowStaticData('global');

// Parse resultJson to find ElevenLabs request_id if exposed
let resultJson = {};
try {
  resultJson = JSON.parse(pollResponse.data.resultJson || '{}');
} catch(e) {}

// ElevenLabs history_item_id is the value to chain as previous_request_ids
// Kie.ai may expose it in resultJson; fallback to taskId
const requestId =
  resultJson.request_id     ||
  resultJson.history_item_id||
  resultJson.requestId      ||
  $('Extract Task ID').item.json.kieTaskId;  // fallback: taskId

// Chain into static data (max 3, ElevenLabs limit)
if (!staticData.ruinsVoicePrevIds) staticData.ruinsVoicePrevIds = [];
staticData.ruinsVoicePrevIds.push(requestId);
if (staticData.ruinsVoicePrevIds.length > 3) {
  staticData.ruinsVoicePrevIds = staticData.ruinsVoicePrevIds.slice(-3);
}

const audioUrl = (pollResponse.data.resultUrls || [])[0] || '';

if (!audioUrl) {
  throw new Error(`Chunk ${chunkMeta.chunkNumber}: no audio URL in kie.ai response`);
}

return [{
  json: {
    ...chunkMeta,
    kieRequestId: requestId,
    audioUrl:     audioUrl,
    chainedIds:   [...staticData.ruinsVoicePrevIds]
  }
}];

const items      = $input.all();
const projVars   = $('Set Project Variables').item.json;
const audioDir   = projVars.projectDir + '/audio';
const padded     = n => String(n).padStart(2, '0');

const lines = items.map((item, i) => {
  const p   = item.json;
  const num = padded(i + 1);
  return [
    `CUE ${num}`,
    `Prompt   : ${p.prompt || p.description || ''}`,
