    `Mood     : ${p.mood || ''}`,
    `Placement: ${p.timestamp || p.placement || ''}`,
    `---`
  ].join('\n');
}).join('\n\n');

const marker  = 'RUINS_MUSIC_EOF';
const writeCmd = [
  `mkdir -p "${audioDir}"`,
  `cat > "${audioDir}/music_prompts.txt" << '${marker}'`,
  `RUINS UNTOLD — MUSIC CUES (${items.length} total)`,
  ``,
  `Generate each cue with your preferred tool and save as:`,
  `  music_cue_01.mp3, music_cue_02.mp3 ... in:`,
  `  ${audioDir}`,
  ``,
  lines,
  marker,
  `echo "Wrote ${items.length} music cues to ${audioDir}/music_prompts.txt"`
].join('\n');

return [{ json: { ...projVars, audioDir, writeCmd, promptCount: items.length, promptType: 'music' } }];

const items      = $input.all();
